import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Creating a fixed-size array of 10 characters
        char[] buffer = new char[10];

        // Copying the user input into the fixed-size buffer with bounds checking
        int maxLength = Math.min(name.length(), buffer.length);
        for (int i = 0; i < maxLength; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Welcome, " + String.valueOf(buffer));

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
